import{_ as t,a as o,b as e,c as d,d as r,e as p}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as l,o as i,c as s,a2 as n}from"./chunks/framework.DnrXFDHb.js";const D=JSON.parse('{"title":"Dropbox チャンネルの追加","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/upload/dropbox.md","filePath":"ja-JP/upload/dropbox.md","lastUpdated":1781962217000}'),h={name:"ja-JP/upload/dropbox.md"};function b(c,a,m,x,u,_){return i(),s("div",null,[...a[0]||(a[0]=[n('<h1 id="dropbox-チャンネルの追加" tabindex="-1">Dropbox チャンネルの追加 <a class="header-anchor" href="#dropbox-チャンネルの追加" aria-label="Permalink to &quot;Dropbox チャンネルの追加&quot;">​</a></h1><p>Dropbox チャンネルは、Dropbox アカウントを ImgBed の保存先として利用するための設定です。</p><h2 id="事前に用意するもの" tabindex="-1">事前に用意するもの <a class="header-anchor" href="#事前に用意するもの" aria-label="Permalink to &quot;事前に用意するもの&quot;">​</a></h2><table tabindex="0"><thead><tr><th>必要なもの</th><th>用途</th></tr></thead><tbody><tr><td>Dropbox アカウント</td><td>ファイルの保存先</td></tr><tr><td>Dropbox App</td><td>API でアクセスするために作成します</td></tr><tr><td>Access Token</td><td>ImgBed から Dropbox へアクセスするために使います</td></tr><tr><td>保存ディレクトリ</td><td>任意。通常は <code>imgbed</code> など</td></tr></tbody></table><h2 id="dropbox-app-を作成する" tabindex="-1">Dropbox App を作成する <a class="header-anchor" href="#dropbox-app-を作成する" aria-label="Permalink to &quot;Dropbox App を作成する&quot;">​</a></h2><p>Dropbox App Console を開き、新しいアプリを作成します。</p><p><img src="'+t+'" alt="アプリ作成" loading="lazy"></p><p>アプリのアクセス範囲は、ImgBed で使う保存先に合わせて選択します。専用フォルダだけを使う運用にすると管理しやすくなります。</p><h2 id="リダイレクト-url-を設定する" tabindex="-1">リダイレクト URL を設定する <a class="header-anchor" href="#リダイレクト-url-を設定する" aria-label="Permalink to &quot;リダイレクト URL を設定する&quot;">​</a></h2><p>OAuth を使う場合は、ImgBed のコールバック URL を Dropbox App に設定します。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://あなたのドメイン/api/oauth/dropbox/callback</span></span></code></pre></div><p><img src="'+o+'" alt="コールバック設定" loading="lazy"></p><h2 id="権限を追加する" tabindex="-1">権限を追加する <a class="header-anchor" href="#権限を追加する" aria-label="Permalink to &quot;権限を追加する&quot;">​</a></h2><p>ファイルのアップロード、読み取り、削除に必要な権限を付与します。</p><p><img src="'+e+'" alt="権限追加" loading="lazy"></p><h2 id="token-を取得する" tabindex="-1">Token を取得する <a class="header-anchor" href="#token-を取得する" aria-label="Permalink to &quot;Token を取得する&quot;">​</a></h2><p>アプリ画面または ImgBed の認証フローから Token を取得します。</p><p><img src="'+d+'" alt="Token 取得" loading="lazy"></p><p>取得した Token をコピーして ImgBed に貼り付けます。</p><p><img src="'+r+'" alt="Token コピー" loading="lazy"></p><h2 id="imgbed-へ入力する" tabindex="-1">ImgBed へ入力する <a class="header-anchor" href="#imgbed-へ入力する" aria-label="Permalink to &quot;ImgBed へ入力する&quot;">​</a></h2><p>アップロード設定で <code>Dropbox</code> を選び、次を入力します。</p><table tabindex="0"><thead><tr><th>項目</th><th>入力内容</th></tr></thead><tbody><tr><td>チャンネル名</td><td>自分が分かる名前</td></tr><tr><td>Access Token</td><td>Dropbox で取得した Token</td></tr><tr><td>保存ディレクトリ</td><td>任意。空欄または <code>imgbed</code></td></tr><tr><td>備考</td><td>任意</td></tr></tbody></table><h2 id="確認方法" tabindex="-1">確認方法 <a class="header-anchor" href="#確認方法" aria-label="Permalink to &quot;確認方法&quot;">​</a></h2><p>保存後、容量確認またはテストアップロードを実行します。</p><p><img src="'+p+'" alt="容量確認" loading="lazy"></p><p>Dropbox 内にファイルが作成され、ImgBed のリンクが開ければ設定完了です。</p><h2 id="よくある確認ポイント" tabindex="-1">よくある確認ポイント <a class="header-anchor" href="#よくある確認ポイント" aria-label="Permalink to &quot;よくある確認ポイント&quot;">​</a></h2><ul><li>Token が期限切れ、または権限不足になっていないか。</li><li>Dropbox App の権限を変更したあと、再認証しているか。</li><li>保存ディレクトリ名に不要なスラッシュや空白が入っていないか。</li><li>Dropbox 側の容量が不足していないか。</li></ul>',29)])])}const f=l(h,[["render",b]]);export{D as __pageData,f as default};
